### Step 2: Set Up the Server

In `server.js`, set up a basic Express server:

```javascript
const express = require('express');
const axios = require('axios');
const path = require('path');
require('dotenv').config();

const app = express();
const PORT = process.env.PORT || 3000;

app.use(express.static(path.join(__dirname, 'public')));
app.set('view engine', 'ejs');

app.get('/weather', async (req, res) => {
    const city = req.query.city;
    const apiKey = process.env.WEATHER_API_KEY;
    const url = `https://api.openweathermap.org/data/2.5/weather?q=${city}&appid=${apiKey}&units=metric`;

    try {
        const response = await axios.get(url);
        res.json(response.data);
    } catch (error) {
        res.status(500).send('Error fetching weather data');
    }
});

app.listen(PORT, () => {
    console.log(`Server is running on http://localhost:${PORT}`);
});
```

### Step 3: Create the Frontend

In `public/index.html`, create a simple HTML interface:

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <link rel="stylesheet" href="styles.css">
    <title>Weather Dashboard</title>
</head>
<body>
    <div class="container">
        <h1>Weather Dashboard</h1>
        <input type="text" id="city" placeholder="Enter city name">
        <button id="getWeather">Get Weather</button>
        <div id="weatherResult"></div>
    </div>
    <script src="script.js"></script>
</body>
</html>
```

In `public/styles.css`, add some basic styles:

```css
body {
    font-family: Arial, sans-serif;
    background-color: #f0f0f0;
    text-align: center;
}

.container {
    margin-top: 50px;
}

input {
    padding: 10px;
    width: 200px;
}

button {
    padding: 10px;
    margin-left: 10px;
}

#weatherResult {
    margin-top: 20px;
}
```

In `public/script.js`, add the JavaScript to fetch weather data:

```javascript
document.getElementById('getWeather').addEventListener('click', async () => {
    const city = document.getElementById('city').value;
    const response = await fetch(`/weather?city=${city}`);
    const data = await response.json();

    const weatherResult = document.getElementById('weatherResult');
    if (response.ok) {
        weatherResult.innerHTML = `
            <h2>${data.name}</h2>
            <p>Temperature: ${data.main.temp} °C</p>
            <p>Weather: ${data.weather[0].description}</p>
        `;
    } else {
        weatherResult.innerHTML = `<p>Error: ${data}</p>`;
    }
});
```

### Step 4: Set Up Environment Variables

In the `.env` file, add your OpenWeatherMap API key:

```
WEATHER_API_KEY=your_api_key_here
```

### Step 5: Run the Application

1. Start the server:
   ```bash
   node server.js
   ```

2. Open your browser and navigate to `http://localhost:3000`.

### Conclusion

You now have a basic Weather Dashboard web app that fetches weather data from the OpenWeatherMap API. You can enhance it further by adding error handling, more styling, or additional features as needed.
